     String // e.g., \"Spring 2025\"\n  year      Int\n  term      String // e.g., \"Spring\", \"Fall\", \"Summer\"\n  startDate DateTime\n  endDate   DateTime\n  isActive  Boolean  @default(false)\n\n  departments   Department[]\n  examTypes     ExamType[]\n  courses       Course[]\n  solverRuns    SolverRun[]\n  solverConfigs SolverConfig[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Department {\n  id        String @id @default(cuid())\n  code      String\n  name      String\n  sessionId String\n\n  session  AcademicSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  subjects Subject[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([code, sessionId])\n}\n\nmodel Subject {\n  id           String @id @default(cuid())\n  code         String // e.g., \"CS\"\n  name         String // e.g., \"Computer Science\"\n  departmentId String\n\n  department Department @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  courses    Course[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([code, departmentId])\n}\n\nmodel Course {\n  id           String @id @default(cuid())\n  courseNumber String // e.g., \"101\"\n  title        String // e.g., \"Intro to CS\"\n  subjectId    String\n  sessionId    String\n\n  subject       Subject         @relation(fields: [subjectId], references: [id], onDelete: Cascade)\n  session       AcademicSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  sections      Section[]\n  sectionGroups SectionGroup[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([courseNumber, subjectId, sessionId])\n}\n\nmodel Section {\n  id            String @id @default(cuid())\n  sectionNumber String // e.g., \"001\"\n  courseId      String\n\n  course           Course               @relation(fields: [courseId], references: [id], onDelete: